fn render_table<W: Write>(
    out: &mut W,
    cli: &Cli,
    records: &[Vec<String>],
    has_header: bool,
) -> io::Result<()> {
    if records.is_empty() {
        // empty input
        let mut col_widths = vec![0usize];
        col_widths.clear();
        return render_empty_table(out, cli, &col_widths);
    }

    let mut records = records.to_vec();

    // Apply -n: prepend # column
    if cli.number {
        let n_data_rows = if has_header { records.len() - 1 } else { records.len() };
        for (i, rec) in records.iter_mut().enumerate() {
            let label = if has_header && i == 0 {
                "#".to_string()
            } else {
                let idx = if has_header { i } else { i + 1 };
                idx.to_string()
            };
            let _ = n_data_rows;
            rec.insert(0, label);
        }
    }

    let num_cols = records[0].len();
    let padding = cli.padding;

    // Compute column widths using sniff
    let mut col_widths = vec![0usize; num_cols];

    // Always include header (records[0]) if has_header
    if has_header {
        for (i, cell) in records[0].iter().enumerate() {
            col_widths[i] = col_widths[i].max(str_width(cell));
        }
    }

    // Include first `sniff` data rows (or all if sniff == 0)
    let data_start = if has_header { 1 } else { 0 };
    let sniff_limit = if cli.sniff == 0 {
        records.len() - data_start
    } else {
        cli.sniff
    };
    for row in records.iter().skip(data_start).take(sniff_limit) {
        for (i, cell) in row.iter().enumerate() {
            if i < num_cols {
                col_widths[i] = col_widths[i].max(str_width(cell));
            }
        }
    }

    // Render
    render_with_widths(out, cli, &records, has_header, &col_widths, padding)
}

fn render_empty_table<W: Write>(out: &mut W, cli: &Cli, col_widths: &[usize]) -> io::Result<()> {
    let style = style_def(cli.style);
    if let Some(top) = style.top {
        format_border(out, cli.indent, top, col_widths, style.outer_pad)?;
    }
    // empty row
    let (left, _, right) = style.row;
    if cli.indent > 0 {
        write!(out, "{}", " ".repeat(cli.indent))?;
    }
    if style.outer_pad > 0 {
        write!(out, "{}", " ".repeat(style.outer_pad))?;
    }
    write!(out, "{}", left)?;
    write!(out, "{}", right)?;
    if style.outer_pad > 0 {
        write!(out, "{}", " ".repeat(style.outer_pad))?;
    }
    writeln!(out)?;
    if let Some(bot) = style.bottom {
        format_border(out, cli.indent, bot, col_widths, style.outer_pad)?;
    }
    Ok(())
}

fn render_with_widths<W: Write>(
    out: &mut W,
    cli: &Cli,
    records: &[Vec<String>],
    has_header: bool,
    col_widths: &[usize],
    padding: usize,
) -> io::Result<()> {
    let style = style_def(cli.style);

    if let Some(top) = style.top {
        format_border(out, cli.indent, top, col_widths, style.outer_pad)?;
    }

    let data_start = if has_header { 1 } else { 0 };

    // Header row
    if has_header && !records.is_empty() {
        format_row(out, cli.indent, &style, &records[0], col_widths, padding, cli.header_align)?;
    }

    // Header/body separator
    let body_exists = records.len() > data_start;
    if has_header && body_exists {
        if let Some(sep) = style.sep {
            format_border(out, cli.indent, sep, col_widths, style.outer_pad)?;
        }
    } else if !has_header && !records.is_empty() {
        // No header — no separator at top of body
    }

    // Body rows
    for (i, rec) in records.iter().enumerate().skip(data_start) {
        format_row(out, cli.indent, &style, rec, col_widths, padding, cli.body_align)?;
        // Body separators (grid style)
        if i + 1 < records.len() {
            if let Some(bs) = style.body_sep {
                format_border(out, cli.indent, bs, col_widths, style.outer_pad)?;
            }
        }
    }

    if let Some(bot) = style.bottom {
        format_border(out, cli.indent, bot, col_widths, style.outer_pad)?;
    }
    Ok(())
}

fn read_all<R: Read>(mut r: R) -> io::Result<Vec<u8>> {
    let mut buf = Vec::new();
    r.read_to_end(&mut buf)?;
    Ok(buf)
}

fn main() -> ExitCode {
    let cli = Cli::parse();

    let _ = cli.disable_pager;

    // Determine delimiter
    let delim = if cli.tsv { b'\t' } else {
        let mut buf = [0u8; 4];
        let s = cli.delimiter.encode_utf8(&mut buf);
        if s.len() == 1 {
            s.as_bytes()[0]
        } else {
            // Multi-byte delim: csv crate only supports single-byte.
            // For multi-byte unicode delim, we'd need custom handling.
            // For now, use the first byte (may not be ideal).
            s.as_bytes()[0]
        }
    };

    // Read input
    let input_bytes: Vec<u8> = if let Some(ref path) = cli.file {
        match File::open(path) {
            Ok(f) => match read_all(BufReader::new(f)) {
                Ok(b) => b,
                Err(e) => {
                    eprintln!("csview: {}", e);
                    return ExitCode::from(1);
                }
            },
            Err(e) => {
                eprintln!("csview: {}", e);
                return ExitCode::from(1);
            }
        }
    } else {
        let stdin = io::stdin().lock();
        match read_all(stdin) {
            Ok(b) => b,
            Err(e) => {
                eprintln!("csview: {}", e);
                return ExitCode::from(1);
            }
        }
    };

    // Strip BOM
    let input_bytes = if input_bytes.starts_with(b"\xef\xbb\xbf") {
        input_bytes[3..].to_vec()
    } else {
        input_bytes
    };

    // Parse CSV
    let mut reader = csv::ReaderBuilder::new()
        .has_headers(false)
        .delimiter(delim)
        .flexible(false)
        .trim(csv::Trim::None)
        .from_reader(&input_bytes[..]);

    let mut records: Vec<Vec<String>> = Vec::new();
    for result in reader.byte_records() {
        match result {
            Ok(rec) => {
                let mut row = Vec::with_capacity(rec.len());
                for field in rec.iter() {
                    match std::str::from_utf8(field) {
                        Ok(s) => row.push(s.to_string()),
                        Err(_) => {
                            // Will be caught by the csv crate's error handling below
                            // (the byte_records iterator doesn't validate UTF-8;
                            // we use string_records for that path).
                            row.push(String::from_utf8_lossy(field).into_owned());
                        }
                    }
                }
                records.push(row);
            }
            Err(e) => {
                eprintln!("csview: CSV error: {}", e);
                return ExitCode::from(1);
            }
        }
    }

    // Now check for UTF-8 errors using a second pass with string_records
    // (We need to do this to get the right error format)
    let mut reader2 = csv::ReaderBuilder::new()
        .has_headers(false)
        .delimiter(delim)
        .flexible(false)
        .trim(csv::Trim::None)
        .from_reader(&input_bytes[..]);
    for result in reader2.records() {
        if let Err(e) = result {
            eprintln!("csview: CSV parse error: {}", e);
            return ExitCode::from(1);
        }
    }

    let has_header = !cli.no_headers;

    let stdout = io::stdout();
    let mut out = BufWriter::new(stdout.lock());
    if let Err(e) = render_table(&mut out, &cli, &records, has_header) {
        if e.kind() == io::ErrorKind::BrokenPipe {
            return ExitCode::from(0);
        }
        eprintln!("csview: {}", e);
        return ExitCode::from(1);
    }
    let _ = out.flush();
    ExitCode::from(0)
}

