98	fn parse_delim(s: &str) -> Result<char, String> {
99	    let mut iter = s.chars();
100	    let c = match iter.next() {
101	        Some(c) => c,
102	        None => return Err("cannot parse char from empty string".to_string()),
103	    };
104	    if iter.next().is_some() {
105	        return Err("too many characters in string".to_string());
106	    }
107	    Ok(c)
108	}
