110	// Width of a single grapheme cluster, matching csview's behavior.
111	fn grapheme_width(g: &str) -> usize {
112	    let mut chars = g.chars();
113	    let first = chars.next();
114	    let second = chars.next();
115	    if let (Some(c), None) = (first, second) {
116	        // Single-char grapheme
117	        if UnicodeWidthChar::width(c).is_none() {
118	            // Control character — csview treats as 1
119	            return 1;
120	        }
121	    }
122	    UnicodeWidthStr::width(g)
123	}
124	
125	fn str_width(s: &str) -> usize {
126	    s.graphemes(true).map(grapheme_width).sum()
127	}
128	
129	fn digit_count(n: usize) -> usize {
130	    if n == 0 { 1 } else {
131	        let mut x = n;
132	        let mut c = 0;
133	        while x > 0 {
134	            x /= 10;
135	            c += 1;
136	        }
137	        c
138	    }
139	}
