141	// Truncate string `s` so that its width is at most `max_w`.
142	// Returns the truncated string and its actual width.
143	fn truncate_to_width(s: &str, max_w: usize) -> (String, usize) {
144	    if str_width(s) <= max_w {
145	        let w = str_width(s);
146	        return (s.to_string(), w);
147	    }
148	    let mut out = String::new();
149	    let mut w = 0;
150	    for g in s.graphemes(true) {
151	        let gw = grapheme_width(g);
152	        if w + gw > max_w {
153	            break;
154	        }
155	        out.push_str(g);
156	        w += gw;
157	    }
158	    (out, w)
159	}
