161	// Pad string with spaces to the given width.
162	fn pad_to(content: &str, content_w: usize, target_w: usize, align: Align) -> String {
163	    if content_w >= target_w {
164	        return content.to_string();
165	    }
166	    let diff = target_w - content_w;
167	    match align {
168	        Align::Left => format!("{}{}", content, " ".repeat(diff)),
169	        Align::Right => format!("{}{}", " ".repeat(diff), content),
170	        Align::Center => {
171	            let left = diff / 2;
172	            let right = diff - left;
173	            format!("{}{}{}", " ".repeat(left), content, " ".repeat(right))
174	        }
175	    }
176	}
