262	fn format_border<W: Write>(
263	    out: &mut W,
264	    indent: usize,
265	    style_parts: (&str, &str, &str, &str),
266	    col_widths: &[usize],
267	    padding: usize,
268	    outer_pad: usize,
269	) -> io::Result<()> {
270	    let (left, fill, middle, right) = style_parts;
271	    if indent > 0 {
272	        write!(out, "{}", " ".repeat(indent))?;
273	    }
274	    if outer_pad > 0 {
275	        write!(out, "{}", " ".repeat(outer_pad))?;
276	    }
277	    write!(out, "{}", left)?;
278	    for (i, &w) in col_widths.iter().enumerate() {
279	        let total = w + 2 * padding;
280	        for _ in 0..total {
281	            write!(out, "{}", fill)?;
282	        }
283	        if i + 1 < col_widths.len() {
284	            write!(out, "{}", middle)?;
285	        }
286	    }
287	    write!(out, "{}", right)?;
288	    if outer_pad > 0 {
289	        write!(out, "{}", " ".repeat(outer_pad))?;
290	    }
291	    writeln!(out)?;
292	    Ok(())
293	}
294	
295	fn format_row<W: Write>(
296	    out: &mut W,
297	    indent: usize,
298	    style: &StyleDef,
299	    cells: &[String],
300	    col_widths: &[usize],
301	    padding: usize,
302	    align: Align,
303	) -> io::Result<()> {
304	    let (left, middle, right) = style.row;
305	    if indent > 0 {
306	        write!(out, "{}", " ".repeat(indent))?;
307	    }
308	    if style.outer_pad > 0 {
309	        write!(out, "{}", " ".repeat(style.outer_pad))?;
310	    }
311	    write!(out, "{}", left)?;
312	    let pad = " ".repeat(padding);
313	    for (i, cell) in cells.iter().enumerate() {
314	        let w = col_widths[i];
315	        // Possibly truncate
316	        let (truncated, tw) = truncate_to_width(cell, w);
317	        let padded = pad_to(&truncated, tw, w, align);
318	        write!(out, "{}{}{}", pad, padded, pad)?;
319	        if i + 1 < cells.len() {
320	            write!(out, "{}", middle)?;
321	        }
322	    }
323	    write!(out, "{}", right)?;
324	    if style.outer_pad > 0 {
325	        write!(out, "{}", " ".repeat(style.outer_pad))?;
326	    }
327	    writeln!(out)?;
328	    Ok(())
329	}
330	
331	fn render_table<W: Write>(
332	    out: &mut W,
333	    cli: &Cli,
334	    records: &[Vec<String>],
335	    has_header: bool,
336	) -> io::Result<()> {
337	    if records.is_empty() {
338	        // empty input
339	        let mut col_widths = vec![0usize];
340	        col_widths.clear();
341	        return render_empty_table(out, cli, &col_widths);
342	    }
343	
344	    let mut records = records.to_vec();
345	
346	    // Apply -n: prepend # column
347	    let data_rows = if has_header { records.len().saturating_sub(1) } else { records.len() };
348	    if cli.number {
349	        for (i, rec) in records.iter_mut().enumerate() {
350	            let label = if has_header && i == 0 {
351	                "#".to_string()
352	            } else {
353	                let idx = if has_header { i } else { i + 1 };
354	                idx.to_string()
355	            };
356	            rec.insert(0, label);
357	        }
358	    }
359	
360	    let num_cols = records[0].len();
361	    let padding = cli.padding;
362	
363	    // Compute column widths using sniff
364	    let mut col_widths = vec![0usize; num_cols];
365	
366	    // For -n column: force col 0 width to digit_count(data_rows + 1)
367	    if cli.number {
368	        let w = digit_count(data_rows + 1);
369	        col_widths[0] = w;
370	    }
371	
372	    // Always include header (records[0]) if has_header
373	    if has_header {
374	        for (i, cell) in records[0].iter().enumerate() {
375	            col_widths[i] = col_widths[i].max(str_width(cell));
376	        }
377	    }
378	
379	    // Include first `sniff` data rows (or all if sniff == 0)
380	    let data_start = if has_header { 1 } else { 0 };
381	    let sniff_limit = if cli.sniff == 0 {
382	        records.len() - data_start
383	    } else {
384	        cli.sniff
385	    };
386	    for row in records.iter().skip(data_start).take(sniff_limit) {
387	        for (i, cell) in row.iter().enumerate() {
388	            if i < num_cols {
389	                col_widths[i] = col_widths[i].max(str_width(cell));
390	            }
391	        }
392	    }
393	
394	    // Render
395	    render_with_widths(out, cli, &records, has_header, &col_widths, padding)
396	}
397	
398	fn render_empty_table<W: Write>(out: &mut W, cli: &Cli, col_widths: &[usize]) -> io::Result<()> {
399	    let style = style_def(cli.style);
400	    if let Some(top) = style.top {
401	        format_border(out, cli.indent, top, col_widths, cli.padding, style.outer_pad)?;
402	    }
403	    // empty row
404	    let (left, _, right) = style.row;
405	    if cli.indent > 0 {
406	        write!(out, "{}", " ".repeat(cli.indent))?;
407	    }
408	    if style.outer_pad > 0 {
409	        write!(out, "{}", " ".repeat(style.outer_pad))?;
410	    }
411	    write!(out, "{}", left)?;
412	    write!(out, "{}", right)?;
413	    if style.outer_pad > 0 {
414	        write!(out, "{}", " ".repeat(style.outer_pad))?;
415	    }
416	    writeln!(out)?;
417	    if let Some(bot) = style.bottom {
418	        format_border(out, cli.indent, bot, col_widths, cli.padding, style.outer_pad)?;
419	    }
420	    Ok(())
421	}
422	
423	fn render_with_widths<W: Write>(
424	    out: &mut W,
425	    cli: &Cli,
426	    records: &[Vec<String>],
427	    has_header: bool,
428	    col_widths: &[usize],
429	    padding: usize,
430	) -> io::Result<()> {
431	    let style = style_def(cli.style);
432	
433	    if let Some(top) = style.top {
434	        format_border(out, cli.indent, top, col_widths, padding, style.outer_pad)?;
435	    }
436	
437	    let data_start = if has_header { 1 } else { 0 };
438	
439	    // Header row
440	    if has_header && !records.is_empty() {
441	        format_row(out, cli.indent, &style, &records[0], col_widths, padding, cli.header_align)?;
442	    }
443	
444	    // Header/body separator
445	    let body_exists = records.len() > data_start;
446	    if has_header && body_exists {
447	        if let Some(sep) = style.sep {
448	            format_border(out, cli.indent, sep, col_widths, padding, style.outer_pad)?;
449	        }
450	    } else if !has_header && !records.is_empty() {
451	        // No header — no separator at top of body
452	    }
453	
454	    // Body rows
455	    for (i, rec) in records.iter().enumerate().skip(data_start) {
456	        format_row(out, cli.indent, &style, rec, col_widths, padding, cli.body_align)?;
457	        // Body separators (grid style)
458	        if i + 1 < records.len() {
459	            if let Some(bs) = style.body_sep {
460	                format_border(out, cli.indent, bs, col_widths, padding, style.outer_pad)?;
461	            }
462	        }
463	    }
464	
465	    if let Some(bot) = style.bottom {
466	        format_border(out, cli.indent, bot, col_widths, padding, style.outer_pad)?;
467	    }
468	    Ok(())
469	}
