471	fn read_all<R: Read>(mut r: R) -> io::Result<Vec<u8>> {
472	    let mut buf = Vec::new();
473	    r.read_to_end(&mut buf)?;
474	    Ok(buf)
475	}
476	
477	fn main() -> ExitCode {
478	    let cli = Cli::parse();
479	
480	    let _ = cli.disable_pager;
481	
482	    // Determine delimiter: use (char as u32) as u8 (low byte). Matches reference behavior
483	    // for multi-byte chars (effectively no-op since the low byte typically isn't in input).
484	    let delim: u8 = if cli.tsv { b'\t' } else { (cli.delimiter as u32) as u8 };
485	
486	    // Read input
487	    let input_bytes: Vec<u8> = if let Some(ref path) = cli.file {
488	        match File::open(path) {
489	            Ok(f) => match read_all(BufReader::new(f)) {
490	                Ok(b) => b,
491	                Err(e) => {
492	                    eprintln!("csview: {}", e);
493	                    return ExitCode::from(1);
494	                }
495	            },
496	            Err(e) => {
497	                eprintln!("csview: {}", e);
498	                return ExitCode::from(1);
499	            }
500	        }
501	    } else {
502	        let stdin = io::stdin().lock();
503	        match read_all(stdin) {
504	            Ok(b) => b,
505	            Err(e) => {
506	                eprintln!("csview: {}", e);
507	                return ExitCode::from(1);
508	            }
509	        }
510	    };
511	
512	    // Strip BOM
513	    let input_bytes = if input_bytes.starts_with(b"\xef\xbb\xbf") {
514	        input_bytes[3..].to_vec()
515	    } else {
516	        input_bytes
517	    };
518	
519	    // Parse CSV
520	    let mut reader = csv::ReaderBuilder::new()
521	        .has_headers(false)
522	        .delimiter(delim)
523	        .flexible(false)
524	        .trim(csv::Trim::None)
525	        .from_reader(&input_bytes[..]);
526	
527	    let mut records: Vec<Vec<String>> = Vec::new();
528	    for result in reader.byte_records() {
529	        match result {
530	            Ok(rec) => {
531	                let mut row = Vec::with_capacity(rec.len());
532	                for field in rec.iter() {
533	                    match std::str::from_utf8(field) {
534	                        Ok(s) => row.push(s.to_string()),
535	                        Err(_) => {
536	                            // Will be caught by the csv crate's error handling below
537	                            // (the byte_records iterator doesn't validate UTF-8;
538	                            // we use string_records for that path).
539	                            row.push(String::from_utf8_lossy(field).into_owned());
540	                        }
541	                    }
542	                }
543	                records.push(row);
544	            }
545	            Err(e) => {
546	                eprintln!("csview: {}", e);
547	                return ExitCode::from(1);
548	            }
549	        }
550	    }
551	
552	    // Now check for UTF-8 errors using a second pass with string_records
553	    // (We need to do this to get the right error format)
554	    let mut reader2 = csv::ReaderBuilder::new()
555	        .has_headers(false)
556	        .delimiter(delim)
557	        .flexible(false)
558	        .trim(csv::Trim::None)
559	        .from_reader(&input_bytes[..]);
560	    for result in reader2.records() {
561	        if let Err(e) = result {
562	            eprintln!("csview: {}", e);
563	            return ExitCode::from(1);
564	        }
565	    }
566	
567	    let has_header = !cli.no_headers;
568	
569	    let stdout = io::stdout();
570	    let mut out = BufWriter::new(stdout.lock());
571	    if let Err(e) = render_table(&mut out, &cli, &records, has_header) {
572	        if e.kind() == io::ErrorKind::BrokenPipe {
573	            return ExitCode::from(0);
574	        }
575	        eprintln!("csview: {}", e);
576	        return ExitCode::from(1);
577	    }
578	    let _ = out.flush();
579	    ExitCode::from(0)
580	}
